#include <bits/stdc++.h>
using namespace std;

const int N=2e5+5;

int n,m,a[N],step[N],pos[N],len;

int cal(int x){
    return x/len+1;
}

int main(){
    scanf("%d",&n);
    for(int i=0;i<n;i++)
        scanf("%d",&a[i]);
    len=sqrt(n);
    for(int i=n-1;i>=0;i--){
        if(i+a[i]>=n || cal(i+a[i])>cal(i))
            step[i]=1,pos[i]=i+a[i];
        else
            step[i]=step[i+a[i]]+1,pos[i]=pos[i+a[i]];
    }
    scanf("%d",&m);
    while(m--){
        int tp,j;
        scanf("%d%d",&tp,&j);
        if(tp==1){
            int p=j,cnt=0;
            while(p<n)
                cnt+=step[p],p=pos[p];
            printf("%d\n",cnt);
        }else{
            int k,l;
            scanf("%d",&k);
            a[j]=k,l=j/len*len;
            for(int i=j;i>=l;i--){
                if(cal(i+a[i])>=n || cal(i+a[i])>cal(i))
                    step[i]=1,pos[i]=i+a[i];
                else
                    step[i]=step[i+a[i]]+1,pos[i]=pos[i+a[i]];
            }
        }
    }
    return 0;
}
